var e=[{id:`L5_1`,type:`dialog`,speaker:`WYLER_CHARADE_NPC_NULL`,text:{KOREA:`쥐새끼처럼 잘도 도망치는 군!`,JPN:`ドブネズミのように逃げ足だけは速いな！`,ENG:`Yes, run like little rats!`,TWN:`和老鼠一樣溜得很快嘛！`},stage:{bg:`BASEMENT`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:`WYLER_CHARADE_NPC_NULL`,text:{KOREA:`계속 그렇게 시간이나 낭비하라고! 어차피 내가 있는 한 이 루트는 절대 안 뚫릴 테니까!`,JPN:`いつまでもそうしてろ！　どうせ俺がいる限りこのルートは絶対に突破できねえからな！`,ENG:`Keep wasting your time like that! As long as I'm here, there's no way you're getting through this route!`,TWN:`你就繼續浪費時間吧！反正只要有我在，這個地方就絕對不會被突破！`},stage:{bg:`BASEMENT`,slots:{L:null,C:null,R:null}}},{id:`L11_1`,type:`dialog`,speaker:`CHOWON_PERSONA_NULL_NULL`,text:{KOREA:`세 발 당, 한 발은 실탄.`,JPN:`3発のうち、1発のみが実弾。`,ENG:`One out of every three shots is a real bullet.`,TWN:`每三發子彈，就有一枚是實彈。`},stage:{bg:`BASEMENT`,slots:{L:{char_id:`CHOWON_PERSONA_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:null}}},{id:`L13_1`,type:`dialog`,speaker:`CHOWON_PERSONA_NULL_NULL`,text:{KOREA:`사격 실력은 그럭저럭 나쁘지 않네. 재장전 시 생기는 간극은 아라크네로 보조하고 있고.`,JPN:`射撃の腕は悪くない。リロードで発生するディレイはアラクネで補っている。`,ENG:`His shooting skills aren't that bad. And the Arachne is covering him while he reloads.`,TWN:`射擊實力還算可以，重新填裝子彈的空隙是以阿拉克涅作為輔助。`},stage:{bg:`BASEMENT`,slots:{L:{char_id:`CHOWON_PERSONA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L14_1`,type:`dialog`,speaker:`CHOWON_PERSONA_NULL_NULL`,text:{KOREA:`수법을 보아하니 로터스의 구더기 출신인가?`,JPN:`このやり方は、ロータスのウジ出身者？`,ENG:`Seeing how he fights, he must be a Maggot from Lotus.`,TWN:`看他的手法，好像來自洛德斯的蛆？`},stage:{bg:`BASEMENT`,slots:{L:{char_id:`CHOWON_PERSONA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L16_1`,type:`dialog`,speaker:`CHOWON_PERSONA_NULL_NULL`,text:{KOREA:`노엘, 이쪽 지하 루트에는 상대 스나이퍼가 대기하고 있어서 돌파는 어렵겠습니다.`,JPN:`ノエル、こちら地下ルートは相手スナイパーが待ち構えているので、突破は難しそうです。`,ENG:`Noelle, the enemy sniper is camping on the underground route. It's going to be difficult to get past him.`,TWN:`洛艾兒，這邊的地下路線有對方的狙擊手在守著，不好突破。`},stage:{bg:`BASEMENT`,slots:{L:{char_id:`CHOWON_PERSONA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`INTERN_FENRIR_NULL_NULL`,face:`UNIT_SERIOUS`}}}},{id:`L17_1`,type:`dialog`,speaker:`CHOWON_PERSONA_NULL_NULL`,text:{KOREA:`지상 상황은 어떻죠?`,JPN:`地上の状況はどうですか？`,ENG:`How's the situation above?`,TWN:`地上的情況怎麼樣？`},stage:{bg:`BASEMENT`,slots:{L:{char_id:`CHOWON_PERSONA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`INTERN_FENRIR_NULL_NULL`,face:`UNIT_SERIOUS`}}}},{id:`L18_1`,type:`dialog`,speaker:`INTERN_FENRIR_NULL_NULL`,text:{KOREA:`여, 여기는……!`,JPN:`こ、こっちは……！`,ENG:`U-up here...!`,TWN:`這，這裡的話……！`},stage:{bg:`BASEMENT`,slots:{L:{char_id:`CHOWON_PERSONA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`INTERN_FENRIR_NULL_NULL`,face:`UNIT_SERIOUS`}}}},{id:`L22_1`,type:`dialog`,speaker:`INTERN_FENRIR_NULL_NULL`,text:{KOREA:`꽥!?`,JPN:`くへっ！？`,ENG:`Eeck?!`,TWN:`啊？！`},stage:{bg:`DOCK_NIGHT`,slots:{L:null,C:{char_id:`INTERN_FENRIR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`ROI_PRYDWEN_NULL_NULL`,text:{KOREA:`괜찮아, 노엘?`,JPN:`大丈夫か、ノエル？`,ENG:`You all right, Noelle?`,TWN:`你沒事吧，洛艾兒？`},stage:{bg:`DOCK_NIGHT`,slots:{L:null,C:{char_id:`ROI_PRYDWEN_NULL_NULL`,face:`UNIT_IDLE`},R:{char_id:`INTERN_FENRIR_NULL_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L27_1`,type:`dialog`,speaker:`ROI_PRYDWEN_NULL_NULL`,text:{KOREA:`뭐야, 이 자식들! 진짜 죽일 생각으로 휘두르고 있잖아?`,JPN:`こいつら！　本当に殺す気で振り回してやがる！`,ENG:`Bollocks! They're really trying to kill us!`,TWN:`這些傢伙怎麼回事！根本是真的要我們的命吧！`},stage:{bg:`DOCK_NIGHT`,slots:{L:null,C:{char_id:`ROI_PRYDWEN_NULL_NULL`,face:`UNIT_IDLE`},R:{char_id:`INTERN_FENRIR_NULL_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L30_1`,type:`dialog`,speaker:`GLITCH_SCAVENGER_NULL_NULL`,text:{KOREA:`오, 맙소사! 그게 무슨 소리야, 형씨?`,JPN:`オーマイガッ！　何言ってんだよ、あんちゃん？`,ENG:`Oh, dear! What are you talking about, man?`,TWN:`喔，我的天！這位小哥你在說什麼呢？`},stage:{bg:`DOCK_NIGHT`,slots:{L:{char_id:`GLITCH_SCAVENGER_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L31_1`,type:`dialog`,speaker:`GLITCH_SCAVENGER_NULL_NULL`,text:{KOREA:`칼을 뽑았으면 당연히 목이라도 썰어야지!`,JPN:`剣を抜いたからには首を切るのは当たり前だろ！`,ENG:`What else am I supposed to do with my sword but cut your throat?!`,TWN:`既然刀已出鞘，當然要對準脖子囉！`},stage:{bg:`DOCK_NIGHT`,slots:{L:null,C:null,R:{char_id:`GLITCH_SCAVENGER_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L32_1`,type:`dialog`,speaker:`GLITCH_SCAVENGER_NULL_NULL`,text:{KOREA:`히히힉. 그래도 넌 말랑말랑해보이니까 예쁘게 잘 썰어 줄게!`,JPN:`ひひひっ。でもお前は柔らかそうだから、綺麗に刻んでやるよ！`,ENG:`Kekeke. You seem soft and tender. I'll cut you up real pretty!`,TWN:`嘻嘻，不過我看你好像很軟很好切，我會把你切得很好看的！`},stage:{bg:`DOCK_NIGHT`,slots:{L:{char_id:`GLITCH_SCAVENGER_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}}}];export{e as default};